<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    dictht </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ht</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 2个哈希表，这也是进行rehash的重要数据结构，从这也看出字典的底层通过哈希表进行实现。</span></span>
